  if (error2.code === "ECONNABORTED" || error2.message?.includes("timeout")) {
    return new Error(`Kimi \u8BF7\u6C42\u8D85\u65F6\uFF0C\u8BF7\u68C0\u67E5\u7F51\u7EDC\u6216\u4EE3\u7406\u8BBE\u7F6E\u3002`);
  }
