var IntegrationManager = class _IntegrationManager {
  /**
   * 私有构造函数
   * 
   * @param context - VS Code 扩展上下文
   */
  constructor(context) {
    /**
     * LangChain 管理器实例
     */
    this.langChainManager = null;
    /**
     * Git 管理器实例
     */
    this.gitManager = null;
    this.context = context;
  }
  static {
    /**
     * 单例实例
     */
    this.instance = null;
  }
  /**
   * 获取单例实例
   * 
   * @param context - VS Code 扩展上下文（首次创建时需要）
   * @returns 集成管理器单例
   */
  static getInstance(context) {
    if (!_IntegrationManager.instance && context) {
      _IntegrationManager.instance = new _IntegrationManager(context);
    }
    return _IntegrationManager.instance;
  }
  /**
   * 重置单例实例
   */
  static resetInstance() {
    _IntegrationManager.instance = null;
  }
  /**
   * 初始化所有集成服务
   * 
   * 初始化 Git 和 LangChain 服务。
   */
  async initialize() {
    await this.initializeGit();
    await this.initializeLangChain();
    this.registerCommands();
  }
  async initializeGit() {
    const workspaceFolders = vscode23.workspace.workspaceFolders;
    if (workspaceFolders && workspaceFolders.length > 0) {
      const repoPath = workspaceFolders[0].uri.fsPath;
      this.gitManager = GitManager.getInstance(repoPath);
      const isGitRepo = await this.gitManager.isGitRepo();
      if (isGitRepo) {
        console.log("Git repository detected and initialized");
      }
    }
  }
  async initializeLangChain() {
    const config2 = vscode23.workspace.getConfiguration("llma");
    const currentModel = config2.get("currentModel") || "deepseek";
    let apiKey = "";
    let baseUrl = "";
    let modelName = "";
    switch (currentModel) {
      case "deepseek":
        apiKey = config2.get("deepseekApiKey") || "";
        modelName = config2.get("deepseekModel") || "deepseek-coder";
        baseUrl = "https://api.deepseek.com/v1";
        break;
      case "qwen":
        apiKey = config2.get("qwenApiKey") || "";
        modelName = config2.get("qwenModel") || "qwen-coder-turbo";
        baseUrl = config2.get("qwenBaseUrl") || "https://dashscope.aliyuncs.com/compatible-mode/v1";
        break;
      case "openai":
        apiKey = config2.get("openaiApiKey") || "";
        modelName = config2.get("openaiModel") || "gpt-4-turbo-preview";
        break;
      case "custom":
        apiKey = config2.get("customModel.apiKey") || "";
        baseUrl = config2.get("customModel.apiBaseUrl") || "";
        modelName = config2.get("customModel.modelName") || "";
        break;
    }
    if (apiKey && modelName) {
      const langChainConfig = {
        apiKey,
        baseUrl: baseUrl || void 0,
        modelName,
        temperature: 0.7,
        maxTokens: 2e3
      };
      this.langChainManager = LangChainManager.getInstance(langChainConfig);
      console.log("LangChain initialized with model:", modelName);
    }
  }
  getLangChainManager() {
    return this.langChainManager;
  }
  getGitManager() {
    return this.gitManager;
  }
  registerCommands() {
    const commands7 = [
      vscode23.commands.registerCommand("llma.git.quickCommit", async () => {
        if (this.gitManager) {
          await this.gitManager.showQuickCommit();
        } else {
          vscode23.window.showErrorMessage("Git manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.git.quickPush", async () => {
        if (this.gitManager) {
          await this.gitManager.showQuickPush();
        } else {
          vscode23.window.showErrorMessage("Git manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.git.quickPull", async () => {
        if (this.gitManager) {
          await this.gitManager.showQuickPull();
        } else {
          vscode23.window.showErrorMessage("Git manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.git.branchPicker", async () => {
        if (this.gitManager) {
          await this.gitManager.showBranchPicker();
        } else {
          vscode23.window.showErrorMessage("Git manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.git.status", async () => {
        if (this.gitManager) {
          await this.gitManager.showStatusOutput();
        } else {
          vscode23.window.showErrorMessage("Git manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.git.aiCommit", async () => {
        if (this.gitManager && this.langChainManager) {
          try {
            const diff = await this.gitManager.getDiff();
            if (!diff.trim()) {
              vscode23.window.showInformationMessage("No changes to commit");
              return;
            }
            const commitMessage = await this.langChainManager.generateCommitMessage(diff);
            const userMessage = await vscode23.window.showInputBox({
              prompt: "AI generated commit message. Edit or confirm:",
              value: commitMessage
            });
            if (userMessage) {
              await this.gitManager.add(".");
              await this.gitManager.commit(userMessage);
              vscode23.window.showInformationMessage("AI commit successful");
            }
          } catch (error2) {
            vscode23.window.showErrorMessage(`AI commit failed: ${error2}`);
          }
        } else {
          vscode23.window.showErrorMessage("Git or LangChain manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.code.explain", async () => {
        const editor = vscode23.window.activeTextEditor;
        if (!editor) {
          vscode23.window.showInformationMessage("No active editor");
          return;
        }
        const selection = editor.selection;
        const code = selection.isEmpty ? editor.document.getText() : editor.document.getText(selection);
        const fileType = editor.document.fileName.split(".").pop() || "txt";
        if (this.langChainManager) {
          try {
            const explanation = await this.langChainManager.explainCode(code, fileType);
            const panel = vscode23.window.createWebviewPanel(
              "codeExplanation",
              "Code Explanation",
              vscode23.ViewColumn.Beside,
              {}
            );
            panel.webview.html = `
              <!DOCTYPE html>
              <html>
              <head>
                <style>
                  body {
                    font-family: var(--vscode-font-family);
                    padding: 20px;
                    color: var(--vscode-foreground);
                    background: var(--vscode-editor-background);
                    white-space: pre-wrap;
                    word-wrap: break-word;
                  }
                </style>
              </head>
              <body>${explanation.replace(/\n/g, "<br>")}</body>
              </html>
            `;
          } catch (error2) {
            vscode23.window.showErrorMessage(`Failed to explain code: ${error2}`);
          }
        } else {
          vscode23.window.showErrorMessage("LangChain manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.code.review", async () => {
        const editor = vscode23.window.activeTextEditor;
        if (!editor) {
          vscode23.window.showInformationMessage("No active editor");
          return;
        }
        const code = editor.document.getText();
        const fileType = editor.document.fileName.split(".").pop() || "txt";
        if (this.langChainManager) {
          try {
            const review = await this.langChainManager.codeReview(code, fileType);
            const panel = vscode23.window.createWebviewPanel(
              "codeReview",
              "Code Review",
              vscode23.ViewColumn.Beside,
              {}
            );
            panel.webview.html = `
              <!DOCTYPE html>
              <html>
              <head>
                <style>
                  body {
                    font-family: var(--vscode-font-family);
                    padding: 20px;
                    color: var(--vscode-foreground);
                    background: var(--vscode-editor-background);
                    white-space: pre-wrap;
                    word-wrap: break-word;
                  }
                </style>
              </head>
              <body>${review.replace(/\n/g, "<br>")}</body>
              </html>
            `;
          } catch (error2) {
            vscode23.window.showErrorMessage(`Failed to review code: ${error2}`);
          }
        } else {
          vscode23.window.showErrorMessage("LangChain manager not initialized");
        }
      }),
      vscode23.commands.registerCommand("llma.code.generateTests", async () => {
        const editor = vscode23.window.activeTextEditor;
        if (!editor) {
          vscode23.window.showInformationMessage("No active editor");
          return;
        }
        const selection = editor.selection;
        const code = selection.isEmpty ? editor.document.getText() : editor.document.getText(selection);
        const fileType = editor.document.fileName.split(".").pop() || "txt";
        if (this.langChainManager) {
          try {
            const tests = await this.langChainManager.generateTests(code, fileType);
            const panel = vscode23.window.createWebviewPanel(
              "testGeneration",
              "Generated Tests",
              vscode23.ViewColumn.Beside,
              { enableScripts: true }
            );
            panel.webview.html = `
              <!DOCTYPE html>
              <html>
              <head>
                <style>
                  body {
                    font-family: var(--vscode-font-family);
                    padding: 20px;
                    color: var(--vscode-foreground);
                    background: var(--vscode-editor-background);
                  }
                  pre {
                    background: var(--vscode-editor-lineHighlightBackground);
                    padding: 15px;
                    border-radius: 4px;
                    overflow-x: auto;
                  }
                  button {
                    background: var(--vscode-button-background);
                    color: var(--vscode-button-foreground);
                    border: none;
                    padding: 8px 16px;
                    border-radius: 4px;
                    cursor: pointer;
                    margin-top: 10px;
                  }
                  button:hover {
                    background: var(--vscode-button-hoverBackground);
                  }
                </style>
              </head>
              <body>
                <pre><code>${tests.replace(/</g, "&lt;").replace(/>/g, "&gt;")}</code></pre>
                <button onclick="copyCode()">Copy to Clipboard</button>
                <script>
                  const vscode = acquireVsCodeApi();
                  function copyCode() {
                    const code = document.querySelector('code').textContent;
                    navigator.clipboard.writeText(code);
                  }
                </script>
              </body>
              </html>
            `;
          } catch (error2) {
            vscode23.window.showErrorMessage(`Failed to generate tests: ${error2}`);
          }
        } else {
          vscode23.window.showErrorMessage("LangChain manager not initialized");
        }
      })
    ];
    commands7.forEach((cmd) => this.context.subscriptions.push(cmd));
  }
  dispose() {
    LangChainManager.resetInstance();
    GitManager.resetInstance();
    _IntegrationManager.resetInstance();
  }
};

