var statusBarItem2;
var globalChatProvider;
var mcpManager;
var integrationManager;
function activate(context) {
  console.log("=== NJUST_AI_Assistant \u5DF2\u6FC0\u6D3B ===");
  initializeASTAnalyzers();
  console.log("\u2705 AST analyzers initialized for supported languages");
  integrationManager = IntegrationManager.getInstance(context);
  integrationManager.initialize().then(() => {
    console.log("\u2705 Integration manager initialized (LangChain + Git)");
  }).catch((err) => {
    console.warn("Integration manager initialization failed:", err);
  });
  statusBarItem2 = createStatusBarItem();
  context.subscriptions.push(statusBarItem2);
  const provider = new LLMAInlineCompletionProvider();
  const selector = { pattern: "**" };
  const inlineProvider = vscode24.languages.registerInlineCompletionItemProvider(selector, provider);
  context.subscriptions.push(inlineProvider);
  const smartProvider = new SmartCompletionProvider();
  const smartInlineProvider = vscode24.languages.registerInlineCompletionItemProvider(
    { pattern: "**" },
    smartProvider
  );
  context.subscriptions.push(smartInlineProvider);
  const chatProvider = new LLMAChatProvider(context);
  globalChatProvider = chatProvider;
  const chatView = vscode24.window.registerWebviewViewProvider("llma.chatView", chatProvider, {
    webviewOptions: { retainContextWhenHidden: true }
    // 隐藏时保留上下文，避免重新加载
  });
  context.subscriptions.push(chatView);
  mcpManager = new MCPManager();
  const config2 = vscode24.workspace.getConfiguration("llma");
  const mcpServers = config2.get("mcp.servers") || [];
  if (mcpServers.length > 0) {
    mcpManager.initializeServers(mcpServers).catch((err) => {
      console.error("MCP initialization error", err);
    });
  }
  const configListener = vscode24.workspace.onDidChangeConfiguration((e) => {
    if (e.affectsConfiguration("llma.mcp.servers")) {
      const newConfig = vscode24.workspace.getConfiguration("llma");
      const newServers = newConfig.get("mcp.servers") || [];
      mcpManager?.disposeAll().then(() => {
        mcpManager?.initializeServers(newServers);
      });
    }
    if (e.affectsConfiguration("llma")) {
      updateStatusBar(false);
    }
  });
  const generateCommand = vscode24.commands.registerCommand("llma.aiCodeComplete", async () => {
    await handleExplicitCodeGeneration();
  });
  const toggleCommand = vscode24.commands.registerCommand("llma.toggle", () => {
    const config3 = vscode24.workspace.getConfiguration("llma");
    const currentState = config3.get("enableAutoCompletion");
    config3.update("enableAutoCompletion", !currentState, vscode24.ConfigurationTarget.Global);
    vscode24.window.showInformationMessage(`LLMA \u81EA\u52A8\u9884\u6D4B\u5DF2${!currentState ? "\u5F00\u542F" : "\u5173\u95ED"}`);
  });
  const manualTriggerCommand = vscode24.commands.registerCommand("llma.trigger", () => {
    vscode24.commands.executeCommand("editor.action.inlineSuggest.trigger");
  });
  const compileCommand = vscode24.commands.registerCommand("llma.compileCurrentFile", async () => {
    const editor = vscode24.window.activeTextEditor;
    if (!editor) {
      vscode24.window.showWarningMessage("\u8BF7\u5148\u6253\u5F00\u4E00\u4E2A\u7F16\u8F91\u5668");
      return;
    }
    await compileFile(editor.document.uri.fsPath);
  });
  const compileWithOptionsCommand = vscode24.commands.registerCommand("llma.compileWithOptions", async () => {
    const editor = vscode24.window.activeTextEditor;
    if (!editor) {
      vscode24.window.showWarningMessage("\u8BF7\u5148\u6253\u5F00\u4E00\u4E2A\u7F16\u8F91\u5668");
      return;
    }
    await showCompilationOptions(editor.document.uri.fsPath);
  });
  const toggleChatAgentModeCommand = vscode24.commands.registerCommand("llma.toggleChatAgentMode", () => {
    globalChatProvider?.postMessageToWebview({ type: "toggleChatAgentMode" });
  });
  context.subscriptions.push(
    generateCommand,
    toggleCommand,
    manualTriggerCommand,
    compileCommand,
    compileWithOptionsCommand,
    toggleChatAgentModeCommand,
    configListener,
    // 确保 MCP 管理器在扩展停用时释放所有连接
    { dispose: () => mcpManager?.disposeAll() }
  );
}
async function deactivate() {
  if (globalChatProvider) {
    await globalChatProvider.saveCurrentSession();
  }
  if (runTerminal) {
    runTerminal.dispose();
  }
  disposeStatusBar();
  await mcpManager?.disposeAll();
  integrationManager?.dispose();
  console.log("LLMA \u5DF2\u505C\u7528");
}
